INSERT INTO songs (song_number, title, artist, composer, language, lyrics_original, chords, original_key, capo, bpm, time_signature, structure, created_by, is_active) VALUES
(31, 'How Great Is Our God', 'Chris Tomlin', 'Chris Tomlin, Jesse Reeves, Ed Cash', 'english',
'[Verse 1]\nThe splendor of the King clothed in majesty\nLet all the earth rejoice all the earth rejoice\nHe wraps Himself in light and darkness tries to hide\nAnd trembles at His voice trembles at His voice\n\n[Chorus]\nHow great is our God sing with me\nHow great is our God and all will see\nHow great how great is our God\n\n[Verse 2]\nAge to age He stands and time is in His hands\nBeginning and the End Beginning and the End\nThe Godhead three in one Father Spirit Son\nThe Lion and the Lamb the Lion and the Lamb\n\n[Bridge]\nName above all names worthy of all praise\nMy heart will sing how great is our God',
'[Verse 1]\n[G]The splendor of the [Em]King clothed in [C]majesty\nLet [D]all the earth rejoice [G]all the earth rejoice\n[G]He wraps Himself in [Em]light and darkness [C]tries to hide\nAnd [D]trembles at His voice [G]trembles at His voice\n\n[Chorus]\n[G]How great is our God [Em]sing with me\n[C]How great is our God and [D]all will see\n[G]How great how [Em]great is our [C]God [D]\n\n[Verse 2]\n[G]Age to age He [Em]stands and time is [C]in His hands\n[D]Beginning and the End [G]Beginning and the End\n[G]The Godhead three in [Em]one Father [C]Spirit Son\n[D]The Lion and the Lamb [G]the Lion and the Lamb\n\n[Bridge]\n[Em]Name above all names [C]worthy of all praise\n[G]My heart will sing how [D]great is our God',
'G', 0, 74, '4/4', 'Verse1, Chorus, Verse2, Chorus, Bridge, Chorus', 1, TRUE),

(32, 'Forever (We Sing Hallelujah)', 'Kari Jobe', 'Brian Johnson, Christa Black Gifford, Gabriel Wilson, Jenn Johnson', 'english',
'[Verse 1]\nThe moon and stars they wept\nThe morning sun was dead\nThe Savior of the world was fallen\nHis body on the cross\nHis blood poured out for us\nThe weight of every curse upon Him\n\n[Chorus]\nOne final breath He gave\nAs heaven looked away\nThe Son of God was laid in darkness\nA battle in the grave\nThe war on death was waged\nThe power of hell forever broken\n\n[Bridge]\nAnd we sing hallelujah\nWe sing hallelujah\nWe sing hallelujah\nThe Lamb has overcome',
'[Verse 1]\n[Am]The moon and stars they [F]wept\nThe morning [C]sun was dead\nThe [G]Savior of the world was [Am]fallen\n[Am]His body on the [F]cross\nHis blood poured [C]out for us\nThe [G]weight of every curse up[Am]on Him\n\n[Chorus]\n[F]One final breath He [Am]gave\nAs heaven [G]looked away\nThe [C]Son of God was laid in [F]darkness\n[F]A battle in the [Am]grave\nThe war on [G]death was waged\nThe [C]power of hell forever [G]broken\n\n[Bridge]\n[F]And we sing halle[C]lujah\n[G]We sing halle[Am]lujah\n[F]We sing halle[C]lujah\nThe [G]Lamb has over[Am]come',
'C', 0, 68, '4/4', 'Verse1, Chorus, Bridge', 1, TRUE),

(33, 'Your Grace Is Enough', 'Matt Maher', 'Matt Maher', 'english',
'[Verse 1]\nGreat is Your faithfulness O God\nYou wrestle with the sinner''s restless heart\nYou lead us by still waters into mercy\nAnd nothing can keep us apart\n\n[Chorus]\nSo remember Your people remember Your children\nRemember Your promise O God\nYour grace is enough Your grace is enough\nYour grace is enough for me\n\n[Verse 2]\nGreat is Your love and justice God of Jacob\nYou use the weak to lead the strong\nYou lead us in the song of Your salvation\nAnd all Your people sing along',
'[Verse 1]\n[G]Great is Your faithful[D]ness O God\n[Em]You wrestle with the sinner''s rest[C]less heart\n[G]You lead us by still [D]waters into mercy\n[Em]And nothing can keep us a[C]part\n\n[Chorus]\n[D]So remember Your [Em]people remember Your [C]children\n[D]Remember Your [G]promise O God\n[C]Your grace is enough [G]Your grace is enough\n[C]Your grace is e[D]nough for [G]me\n\n[Verse 2]\n[G]Great is Your love and [D]justice God of Jacob\n[Em]You use the weak to lead the [C]strong\n[G]You lead us in the song [D]of Your salvation\n[Em]And all Your people sing a[C]long',
'G', 0, 72, '4/4', 'Verse1, Chorus, Verse2, Chorus', 1, TRUE),

(34, 'Blessed Be Your Name', 'Matt Redman', 'Matt Redman, Beth Redman', 'english',
'[Verse 1]\nBlessed be Your name in the land that is plentiful\nWhere Your streams of abundance flow\nBlessed be Your name\nBlessed be Your name when I''m found in the desert place\nThough I walk through the wilderness\nBlessed be Your name\n\n[Chorus]\nEvery blessing You pour out I''ll turn back to praise\nWhen the darkness closes in Lord still I will say\nBlessed be the name of the Lord\nBlessed be Your name\nBlessed be the name of the Lord\nBlessed be Your glorious name\n\n[Verse 2]\nBlessed be Your name when the sun''s shining down on me\nWhen the world''s all as it should be\nBlessed be Your name\nBlessed be Your name on the road marked with suffering\nThough there''s pain in the offering\nBlessed be Your name',
'[Verse 1]\n[A]Blessed be Your name [E]in the land that is plentiful\n[F#m]Where Your streams of [D]abundance flow\n[A]Blessed be Your name [E]\n[A]Blessed be Your name [E]when I''m found in the desert place\n[F#m]Though I walk thro the [D]wilderness\n[A]Blessed be Your name [E]\n\n[Chorus]\n[A]Every blessing You pour out I''ll [E]turn back to praise\n[F#m]When the darkness closes in Lord [D]still I will say\n[A]Blessed be the name [E]of the Lord\n[F#m]Blessed be Your name [D]\n[A]Blessed be the name [E]of the Lord\n[F#m]Blessed be Your glo[D]rious name\n\n[Verse 2]\n[A]Blessed be Your name [E]when the sun''s shining down on me\n[F#m]When the world''s all as it [D]should be\n[A]Blessed be Your name [E]\n[A]Blessed be Your name [E]on the road marked with suffering\n[F#m]Though there''s pain in the [D]offering\n[A]Blessed be Your name [E]',
'A', 0, 138, '4/4', 'Verse1, Chorus, Verse2, Chorus', 1, TRUE),

(35, 'How He Loves', 'David Crowder Band', 'John Mark McMillan', 'english',
'[Verse 1]\nHe is jealous for me loves like a hurricane\nI am a tree bending beneath the weight of His wind and mercy\nWhen all of a sudden I am unaware of these afflictions eclipsed by glory\nAnd I realize just how beautiful You are\nAnd how great Your affections are for me\n\n[Chorus]\nAnd oh how He loves us oh\nOh how He loves us how He loves us all\nHow He loves us oh\n\n[Verse 2]\nWe are His portion and He is our prize\nDrawn to redemption by the grace in His eyes\nIf His grace is an ocean we''re all sinking\nAnd heaven meets earth like a sloppy wet kiss\nAnd my heart turns violently inside of my chest',
'[Verse 1]\n[C]He is jealous for me loves like a [G]hurricane\nI am a tree bending beneath the weight of His [Am]wind and mercy\n[F]When all of a sudden I am unaware of these [C]afflictions eclipsed by glory\n[G]And I realize just how beautiful You are\nAnd how [Am]great Your affections are for [F]me\n\n[Chorus]\n[C]And oh how He loves [G]us oh\n[Am]Oh how He loves us [F]how He loves us all\n[C]How He loves us [G]oh [Am] [F]\n\n[Verse 2]\n[C]We are His portion and He is our [G]prize\nDrawn to redemption by the grace in His [Am]eyes\n[F]If His grace is an ocean we''re all [C]sinking\n[G]And heaven meets earth like a sloppy wet kiss\n[Am]And my heart turns violently in[F]side of my chest',
'C', 0, 68, '4/4', 'Verse1, Chorus, Verse2, Chorus', 1, TRUE),

(36, 'Our God', 'Chris Tomlin', 'Chris Tomlin, Jesse Reeves, Matt Redman, Jonas Myrin', 'english',
'[Verse 1]\nWater You turned into wine\nOpened the eyes of the blind\nThere''s no one like You none like You\n\n[Verse 2]\nInto the darkness You shine\nOut of the ashes we rise\nThere''s no one like You none like You\n\n[Chorus]\nOur God is greater our God is stronger\nGod You are higher than any other\nOur God is Healer awesome in power\nOur God our God\n\n[Bridge]\nAnd if our God is for us then who could ever stop us\nAnd if our God is with us then what could stand against',
'[Verse 1]\n[Em]Water You turned into [C]wine\n[G]Opened the eyes of the [D]blind\n[Em]There''s no one like You [C]none like [G]You [D]\n\n[Verse 2]\n[Em]Into the darkness You [C]shine\n[G]Out of the ashes we [D]rise\n[Em]There''s no one like You [C]none like [G]You [D]\n\n[Chorus]\n[G]Our God is greater [D]our God is stronger\n[Em]God You are higher than [C]any other\n[G]Our God is Healer [D]awesome in power\n[Em]Our God [C]our God [G\n\n[Bridge]\n[Em]And if our God is for us then [C]who could ever stop us\n[G]And if our God is with us then [D]what could stand against',
'G', 0, 93, '4/4', 'Verse1, Verse2, Chorus, Bridge, Chorus', 1, TRUE),

(37, 'Everlasting God', 'Lincoln Brewster', 'Brenton Brown, Ken Riley', 'english',
'[Verse 1]\nStrength will rise as we wait upon the Lord\nWe will wait upon the Lord\nWe will wait upon the Lord\nStrength will rise as we wait upon the Lord\nWe will wait upon the Lord\nWe will wait upon the Lord\n\n[Chorus]\nOur God You reign forever\nOur hope our strong Deliverer\nYou are the everlasting God\nThe everlasting God\nYou do not faint You won''t grow weary\n\n[Bridge]\nYou''re the defender of the weak\nYou comfort those in need\nYou lift us up on wings like eagles',
'[Verse 1]\n[G]Strength will rise as we [D]wait upon the Lord\n[Em]We will wait upon the [C]Lord\n[G]We will wait upon the [D]Lord\n[G]Strength will rise as we [D]wait upon the Lord\n[Em]We will wait upon the [C]Lord\n[G]We will wait upon the [D]Lord\n\n[Chorus]\n[Em]Our God You reign for[C]ever\n[G]Our hope our strong De[D]liverer\n[Em]You are the ever[C]lasting God\nThe ever[G]lasting God [D]\n[Em]You do not faint You won''t grow [C]weary [G]\n\n[Bridge]\n[Em]You''re the defender of the [C]weak\n[G]You comfort those in [D]need\n[Em]You lift us up on wings like [C]eagles [G]',
'G', 0, 80, '4/4', 'Verse1, Chorus, Bridge, Chorus', 1, TRUE),

(38, 'Shout To The Lord', 'Darlene Zschech', 'Darlene Zschech', 'english',
'[Verse 1]\nMy Jesus my Saviour\nLord there is none like You\nAll of my days I want to praise\nThe wonders of Your mighty love\nMy comfort my shelter\nTower of refuge and strength\nLet every breath all that I am\nNever cease to worship You\n\n[Chorus]\nShout to the Lord all the earth let us sing\nPower and majesty praise to the King\nMountains bow down and the seas will roar\nAt the sound of Your name\nI sing for joy at the work of Your hands\nForever I''ll love You forever I''ll stand\nNothing compares to the promise I have in You',
'[Verse 1]\n[D]My Jesus my [G]Saviour\n[D]Lord there is [A]none like You\n[Bm]All of my days [G]I want to praise\n[A]The wonders of Your mighty [D]love\n[D]My comfort my [G]shelter\n[D]Tower of refuge and [A]strength\n[Bm]Let every breath [G]all that I am\n[A]Never cease to wor[D]ship You\n\n[Chorus]\n[G]Shout to the Lord all the earth let us [D]sing\n[A]Power and majesty praise to the [Bm]King\n[G]Mountains bow down and the [D]seas will roar\nAt the [A]sound of Your name [D]\n[G]I sing for joy at the work of Your [D]hands\n[A]Forever I''ll love You forever I''ll [Bm]stand\n[G]Nothing compares to the promise I have in [D]You',
'D', 0, 72, '4/4', 'Verse1, Chorus', 1, TRUE),

(39, 'Lord I Lift Your Name On High', 'Rick Founds', 'Rick Founds', 'english',
